SELECT service_id, date 
FROM calendar_dates 
WHERE date LIKE '____-06-%' OR date LIKE '____-07-%' OR date LIKE '____-08-%';

SELECT * 
FROM shapes
WHERE shape_pt_sequence < 10;

SELECT DISTINCT trip_id
FROM stop_times
WHERE departure_time > arrival_time;

external_knowledge:
- 'veins of the city's transportation system' refers to the interconnected network of routes;
- 'sailing towards the horizon' metaphorically signifies the destination or headsign of the trips;
- 'coordinates and sequences of the path they follow' corresponds to the latitude, longitude, and sequence of the shape points;
- 'stops they visit with their arrival and departure times' refers to the schedule of stops;
- 'patterns of their departure waves' metaphorically indicates the start time, end time, and headway (interval) of the frequencies;
- 'type of vessel' implies the mode of transport such as bus or rail represented by the route type.

sql:
SELECT route_short_name, route_long_name, route_desc
FROM routes
WHERE route_id > 0;

SELECT AVG(block_capacity) AS average_capacity
FROM blocks
WHERE block_description LIKE '%special%' AND block_description LIKE '%events%';

SELECT DISTINCT s.stop_name
FROM stops s
INNER JOIN routes r ON s.stop_name LIKE '%' || r.route_short_name || '%';

SELECT trip_id, trip_capacity
FROM trips
WHERE trip_capacity > (
    SELECT AVG(trip_capacity) FROM trips
)
ORDER BY trip_capacity DESC;

SELECT trip_id, trip_capacity
FROM trips
WHERE trip_capacity > 50;
